class Solution:
    def minMoves(self, nums, limit):
        n = len(nums)
        m = n // 2
        best = float('inf')
        for target in range(2, 2 * limit + 1):
            total = 0
            for i in range(m):
                a, b = nums[i], nums[n - 1 - i]
                lo, hi = min(a, b), max(a, b)
                if a + b == target:
                    total += 0
                elif lo + 1 <= target <= hi + limit:
                    total += 1
                else:
                    total += 2
            if total < best:
                best = total
        return best

