var minMoves = function(nums, limit) {
    const n = nums.length;
    const m = Math.floor(n / 2);
    const diff = new Array(2 * limit + 2).fill(0);
    diff[2] += 2 * m;
    diff[2 * limit + 1] -= 2 * m;
    for (let i = 0; i < m; i++) {
        const a = nums[i], b = nums[n - 1 - i];
        const lo = Math.min(a, b), hi = Math.max(a, b);
        const s = a + b;
        diff[lo + 1] -= 1;
        diff[hi + limit + 1] += 1;
        diff[s] -= 1;
        diff[s + 1] += 1;
    }
    let best = Infinity;
    let cur = 0;
    for (let x = 2; x <= 2 * limit; x++) {
        cur += diff[x];
        if (cur < best) best = cur;
    }
    return best;
};
